/* DCP_ZP_UD - arithmetic */
static void inst_DCP_ZP_UD(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t m = mos6502_read_byte(cpu, inst->zp);
    m = (uint8_t)(m - 1u);
    mos6502_write_byte(cpu, inst->zp, m);
    uint8_t a = cpu->registers[REG_A];
    uint16_t diff = (uint16_t)a - (uint16_t)m;
    cpu->flags.C = (a >= m);
    cpu->flags.Z = (((uint8_t)diff) == 0u);
    cpu->flags.N = ((((uint8_t)diff) & 0x80u) != 0u);
}

/* DCP_ABS_UD - arithmetic */
static void inst_DCP_ABS_UD(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t m = mos6502_read_byte(cpu, inst->addr);
    m = (uint8_t)(m - 1u);
    mos6502_write_byte(cpu, inst->addr, m);
    uint8_t a = cpu->registers[REG_A];
    uint16_t diff = (uint16_t)a - (uint16_t)m;
    cpu->flags.C = (a >= m);
    cpu->flags.Z = (((uint8_t)diff) == 0u);
    cpu->flags.N = ((((uint8_t)diff) & 0x80u) != 0u);
}

/* ISC_ZP_UD - arithmetic */
static void inst_ISC_ZP_UD(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t m = mos6502_read_byte(cpu, inst->zp);
    m = (uint8_t)(m + 1u);
    mos6502_write_byte(cpu, inst->zp, m);
    uint8_t a = cpu->registers[REG_A];
    uint8_t carry_in = cpu->flags.C ? 1u : 0u;
    uint16_t sub = (uint16_t)m + (uint16_t)(1u - carry_in);
    uint16_t wide = (uint16_t)a - sub;
    uint8_t r = (uint8_t)wide;
    cpu->registers[REG_A] = r;
    cpu->flags.C = ((uint16_t)a >= sub);
    cpu->flags.Z = (r == 0u);
    cpu->flags.N = ((r & 0x80u) != 0u);
    cpu->flags.V = ((((a ^ m) & (a ^ r)) & 0x80u) != 0u);
}

/* ISC_ABS_UD - arithmetic */
static void inst_ISC_ABS_UD(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t m = mos6502_read_byte(cpu, inst->addr);
    m = (uint8_t)(m + 1u);
    mos6502_write_byte(cpu, inst->addr, m);
    uint8_t a = cpu->registers[REG_A];
    uint8_t carry_in = cpu->flags.C ? 1u : 0u;
    uint16_t sub = (uint16_t)m + (uint16_t)(1u - carry_in);
    uint16_t wide = (uint16_t)a - sub;
    uint8_t r = (uint8_t)wide;
    cpu->registers[REG_A] = r;
    cpu->flags.C = ((uint16_t)a >= sub);
    cpu->flags.Z = (r == 0u);
    cpu->flags.N = ((r & 0x80u) != 0u);
    cpu->flags.V = ((((a ^ m) & (a ^ r)) & 0x80u) != 0u);
}

/* SLO_ZP_UD - arithmetic */
static void inst_SLO_ZP_UD(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t m = mos6502_read_byte(cpu, inst->zp);
    cpu->flags.C = ((m & 0x80u) != 0u);
    m = (uint8_t)(m << 1);
    mos6502_write_byte(cpu, inst->zp, m);
    cpu->registers[REG_A] = (uint8_t)(cpu->registers[REG_A] | m);
    cpu->flags.Z = (cpu->registers[REG_A] == 0u);
    cpu->flags.N = ((cpu->registers[REG_A] & 0x80u) != 0u);
}

