/* RRA_ZP_UD - arithmetic */
static void inst_RRA_ZP_UD(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t m = mos6502_read_byte(cpu, inst->zp);
    uint8_t rotate_carry_in = cpu->flags.C ? 1u : 0u;
    cpu->flags.C = ((m & 0x01u) != 0u);
    m = (uint8_t)((m >> 1) | (uint8_t)(rotate_carry_in << 7));
    mos6502_write_byte(cpu, inst->zp, m);
    uint8_t a = cpu->registers[REG_A];
    uint8_t adc_carry_in = cpu->flags.C ? 1u : 0u;
    uint16_t sum = (uint16_t)a + (uint16_t)m + (uint16_t)adc_carry_in;
    uint8_t r = (uint8_t)sum;
    cpu->registers[REG_A] = r;
    cpu->flags.C = (sum > 0xFFu);
    cpu->flags.Z = (r == 0u);
    cpu->flags.N = ((r & 0x80u) != 0u);
    cpu->flags.V = ((((~(a ^ m)) & (a ^ r)) & 0x80u) != 0u);
}

/* RRA_ABS_UD - arithmetic */
static void inst_RRA_ABS_UD(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t m = mos6502_read_byte(cpu, inst->addr);
    uint8_t rotate_carry_in = cpu->flags.C ? 1u : 0u;
    cpu->flags.C = ((m & 0x01u) != 0u);
    m = (uint8_t)((m >> 1) | (uint8_t)(rotate_carry_in << 7));
    mos6502_write_byte(cpu, inst->addr, m);
    uint8_t a = cpu->registers[REG_A];
    uint8_t adc_carry_in = cpu->flags.C ? 1u : 0u;
    uint16_t sum = (uint16_t)a + (uint16_t)m + (uint16_t)adc_carry_in;
    uint8_t r = (uint8_t)sum;
    cpu->registers[REG_A] = r;
    cpu->flags.C = (sum > 0xFFu);
    cpu->flags.Z = (r == 0u);
    cpu->flags.N = ((r & 0x80u) != 0u);
    cpu->flags.V = ((((~(a ^ m)) & (a ^ r)) & 0x80u) != 0u);
}

