/* ARR_IMM_UD - logic */
static void inst_ARR_IMM_UD(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t t = (uint8_t)(cpu->registers[REG_A] & inst->imm);
    uint8_t carry_in = cpu->flags.C ? 1u : 0u;
    uint8_t r = (uint8_t)((t >> 1) | (uint8_t)(carry_in << 7));
    cpu->registers[REG_A] = r;
    cpu->flags.Z = (r == 0u);
    cpu->flags.N = ((r & 0x80u) != 0u);
    cpu->flags.C = ((r & 0x40u) != 0u);
    cpu->flags.V = ((((r >> 6) ^ (r >> 5)) & 0x01u) != 0u);
}

/* AXS_IMM_UD - arithmetic */
static void inst_AXS_IMM_UD(CPUState *cpu, DecodedInstruction *inst) {
    uint8_t ax = (uint8_t)(cpu->registers[REG_A] & cpu->registers[REG_X]);
    uint16_t diff = (uint16_t)ax - (uint16_t)inst->imm;
    uint8_t r = (uint8_t)diff;
    cpu->registers[REG_X] = r;
    cpu->flags.C = (ax >= inst->imm);
    cpu->flags.Z = (r == 0u);
    cpu->flags.N = ((r & 0x80u) != 0u);
}

